class Solution {
public:
    long long maximumOr(vector<int>& nums, int k) {
        int bits = 30;
        long long ans = 0;
        for (int i = bits; i >= 0; --i) {
            long long curr = ans | (1LL << i);
            int ops = 0;
            for (int x : nums) {
                if ((x | curr) != curr) {
                    if (x * (1 << i) | curr == curr) ++ops;
                }
            }
            if (ops <= k) ans = curr;
        }
        return ans;
    }
};
